    for section in elf.iter_sections():
        if isinstance(section, SymbolTableSection) and section.name == '.dynsym':
            targets = [0x2f4b20, 0x2f4c84]
            syms = [(s.name, s['st_value'], s['st_size']) for s in section.iter_symbols() 
                    if s['st_value'] > 0 and s['st_size'] > 0]
            syms.sort(key=lambda x: x[1])
            for addr in targets:
                # find containing
                found = False
                for name, val, size in syms:
                    if val <= addr < val + size:
                        print(f'0x{addr:x}: {name} (+0x{addr - val:x})')
                        found = True
                        break
                if not found:
                    candidates = [(n, v, s) for n, v, s in syms if v <= addr]
                    if candidates:
                        b = candidates[-1]
                        print(f'0x{addr:x}: nearest = {b[0]} at 0x{b[1]:x} size=0x{b[2]:x} (+0x{addr-b[1]:x})')
