from elftools.elf.elffile import ELFFile

with open('libmonosgen-2.0.so.dbg', 'rb') as f:
    elf = ELFFile(f)
    dwarf = elf.get_dwarf_info()
    targets = {0x2f4b20, 0x2f4c84}

    for cu in dwarf.iter_CUs():
        lp = dwarf.line_program_for_CU(cu)
        if lp is None:
            continue
        for entry in lp.get_entries():
            if entry.state and entry.state.address in targets:
                fname = lp['file_entry'][entry.state.file - 1].name.decode()
                print(f"0x{entry.state.address:x}: {fname}:{entry.state.line}")
                targets.discard(entry.state.address)
                if not targets:
                    break
        if not targets:
            break

    # If not exact match, find nearest
    if targets:
        print(f"No exact line match for: {[hex(t) for t in targets]}")
        # Try finding by range
        for cu in dwarf.iter_CUs():
            lp = dwarf.line_program_for_CU(cu)
            if lp is None:
                continue
            entries = [(e.state.address, e.state.file, e.state.line) 
                      for e in lp.get_entries() if e.state and not e.state.end_sequence]
            entries.sort()
            for t in list(targets):
                # binary search for nearest
                import bisect
                addrs = [e[0] for e in entries]
                idx = bisect.bisect_right(addrs, t) - 1
                if idx >= 0 and t - entries[idx][0] < 0x100:
                    fname = lp['file_entry'][entries[idx][1] - 1].name.decode()
                    print(f"0x{t:x}: ~{fname}:{entries[idx][2]} (offset from 0x{entries[idx][0]:x})")
                    targets.discard(t)
            if not targets:
                break
