# These are in the Cortex-A53 erratum thunk section at the end of .text
# The thunk name format is __CortexA53843419_<ADDR> where ADDR is the patched instruction location
# So for 0x2f4b20 and 0x2f4c84, let me find what thunks are at those exact addresses
python3 -c "
from elftools.elf.elffile import ELFFile
from elftools.elf.sections import SymbolTableSection

with open('libmonosgen-2.0.so.dbg', 'rb') as f:
    elf = ELFFile(f)
    symtab = elf.get_section_by_name('.symtab')
    targets = [0x2f4b20, 0x2f4c84]
    for s in symtab.iter_symbols():
        if s['st_value'] in targets or (s['st_value'] <= targets[0] <= s['st_value']+s['st_size']) or \
           (s['st_value'] <= targets[1] <= s['st_value']+s['st_size']):
            if s.name.startswith('__Cortex'):
                pass  # skip
            elif s['st_value'] > 0x2f0000 and s['st_value'] < 0x300000:
                print(f'{s.name} at 0x{s[\"st_value\"]:x} size=0x{s[\"st_size\"]:x}')

    # Find any thunks at exact addresses
    for s in symtab.iter_symbols():
        if s['st_value'] <= 0x2f4b20 < s['st_value'] + max(s['st_size'], 8):
            if '2f4' in hex(s['st_value']):
                print(f'Contains 0x2f4b20: {s.name} at 0x{s[\"st_value\"]:x} size={s[\"st_size\"]}')
        if s['st_value'] <= 0x2f4c84 < s['st_value'] + max(s['st_size'], 8):
            if '2f4' in hex(s['st_value']):
                print(f'Contains 0x2f4c84: {s.name} at 0x{s[\"st_value\"]:x} size={s[\"st_size\"]}')
"", "description": "Find exact thunk symbols at addresses"}
